class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = getDepth(nums[i]);
        }

        int[] prefixSum = new int[n + 1];
        for (int i = 0; i < n; i++) {
            for (int k = 0; k <= 5; k++) {
                if (depths[i] == k) {
                    prefixSum[k * n + i + 1]++;
                }
            }
        }
        for (int i = 1; i <= 5 * n; i++) {
            prefixSum[i] += prefixSum[i - 1];
        }

        int q = queries.length;
        int[] ans = new int[q];
        for (int i = 0; i < q; i++) {
            if (queries[i][0] == 1) {
                int l = (int) queries[i][1];
                int r = (int) queries[i][2];
                int k = (int) queries[i][3];
                ans[i] = prefixSum[k * n + r + 1] - prefixSum[k * n + l];
            } else {
                int idx = (int) queries[i][1];
                int val = (int) queries[i][2];
                nums[idx] = val;
                depths[idx] = getDepth(val);
                for (int j = idx + 1; j <= n; j++) {
                    if (j <= n) {
                        for (int k = 0; k <= 5; k++) {
                            if (depths[j - 1] == k) {
                                prefixSum[k * n + j]++;
                            } else {
                                prefixSum[k * n + j]--;
                            }
                        }
                    }
                }
                for (int j = 5 * n; j >= 0; j--) {
                    prefixSum[j] += prefixSum[j - 1];
                }
            }
        }
        return ans;
    }

    private int getDepth(long x) {
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
}
